window.BIBLE = window.BIBLE || {};
window.BIBLE["Lamentations"] = {"1":{"chapter":"1","title":"JERUSALEM SITS SOLITARY","verses":{"1":{"text":"How doth the city sit solitary, that was full of people! how is she become as a widow! she that was great among the nations, and princess among the provinces, how is she become tributary!","ref":"Lamentations 1:1","synthesized":"How lonely lies the city, once so full of people! She who was great among the nations has become a widow. The princess of the provinces has become a slave.","sources":{"KJV":{"text":"How doth the city sit solitary, that was full of people! how is she become as a widow! she that was great among the nations, and princess among the provinces, how is she become tributary!"},"BSB":{"text":"How lonely lies the city, once so full of people! She who was great among the nations has become a widow. The princess of the provinces has become a slave."}},"definableWords":["people","great","nations","widow"],"peopleInVerse":[]},"2":{"text":"She weepeth sore in the night, and her tears are on her cheeks: among all her lovers she hath none to comfort her: all her friends have dealt treacherously with her, they are become her enemies.","ref":"Lamentations 1:2","synthesized":"She weeps aloud in the night, with tears upon her cheeks. Among all her lovers there is no one to comfort her. All her friends have betrayed her; they have become her enemies.","sources":{"KJV":{"text":"She weepeth sore in the night, and her tears are on her cheeks: among all her lovers she hath none to comfort her: all her friends have dealt treacherously with her, they are become her enemies."},"BSB":{"text":"She weeps aloud in the night, with tears upon her cheeks. Among all her lovers there is no one to comfort her. All her friends have betrayed her; they have become her enemies."}},"definableWords":["night","one"],"peopleInVerse":[]},"3":{"text":"Judah is gone into captivity because of affliction, and because of great servitude: she dwelleth among the heathen, she findeth no rest: all her persecutors overtook her between the straits.","ref":"Lamentations 1:3","synthesized":"Judah has gone into exile under affliction and harsh slavery; she dwells among the nations but finds no place to rest. All her pursuers have overtaken her in the midst of her distress.","sources":{"KJV":{"text":"Judah is gone into captivity because of affliction, and because of great servitude: she dwelleth among the heathen, she findeth no rest: all her persecutors overtook her between the straits."},"BSB":{"text":"Judah has gone into exile under affliction and harsh slavery; she dwells among the nations but finds no place to rest. All her pursuers have overtaken her in the midst of her distress."}},"definableWords":["Judah","nations","rest"],"peopleInVerse":[]},"4":{"text":"The ways of Zion do mourn, because none come to the solemn feasts: all her gates are desolate: her priests sigh, her virgins are afflicted, and she is in bitterness.","ref":"Lamentations 1:4","synthesized":"The roads to Zion mourn, because no one comes to her appointed feasts. All her gates are deserted; her priests groan, her maidens grieve, and she herself is bitter with anguish.","sources":{"KJV":{"text":"The ways of Zion do mourn, because none come to the solemn feasts: all her gates are desolate: her priests sigh, her virgins are afflicted, and she is in bitterness."},"BSB":{"text":"The roads to Zion mourn, because no one comes to her appointed feasts. All her gates are deserted; her priests groan, her maidens grieve, and she herself is bitter with anguish."}},"definableWords":["Zion","one"],"peopleInVerse":[]},"5":{"text":"Her adversaries are the chief, her enemies prosper; for the LORD hath afflicted her for the multitude of her transgressions: her children are gone into captivity before the enemy.","ref":"Lamentations 1:5","synthesized":"Her foes have become her masters; her enemies are at ease. For the LORD has brought her grief because of her many transgressions. Her children have gone away as captives before the enemy.","sources":{"KJV":{"text":"Her adversaries are the chief, her enemies prosper; for the LORD hath afflicted her for the multitude of her transgressions: her children are gone into captivity before the enemy."},"BSB":{"text":"Her foes have become her masters; her enemies are at ease. For the LORD has brought her grief because of her many transgressions. Her children have gone away as captives before the enemy."}},"definableWords":["LORD"],"peopleInVerse":[]},"6":{"text":"And from the daughter of Zion all her beauty is departed: her princes are become like harts that find no pasture, and they are gone without strength before the pursuer.","ref":"Lamentations 1:6","synthesized":"All the splendor has departed from the Daughter of Zion. Her princes are like deer that find no pasture; they lack the strength to flee in the face of the hunter.","sources":{"KJV":{"text":"And from the daughter of Zion all her beauty is departed: her princes are become like harts that find no pasture, and they are gone without strength before the pursuer."},"BSB":{"text":"All the splendor has departed from the Daughter of Zion. Her princes are like deer that find no pasture; they lack the strength to flee in the face of the hunter."}},"definableWords":["daughter","Zion"],"peopleInVerse":[]},"7":{"text":"Jerusalem remembered in the days of her affliction and of her miseries all her pleasant things that she had in the days of old, when her people fell into the hand of the enemy, and none did help her: the adversaries saw her, and did mock at her sabbaths.","ref":"Lamentations 1:7","synthesized":"In the days of her affliction and wandering Jerusalem remembers all the treasures that were hers in days of old. When her people fell into enemy hands she received no help. Her enemies looked upon her, laughing at her downfall.","sources":{"KJV":{"text":"Jerusalem remembered in the days of her affliction and of her miseries all her pleasant things that she had in the days of old, when her people fell into the hand of the enemy, and none did help her: the adversaries saw her, and did mock at her sabbaths."},"BSB":{"text":"In the days of her affliction and wandering Jerusalem remembers all the treasures that were hers in days of old. When her people fell into enemy hands she received no help. Her enemies looked upon her, laughing at her downfall."}},"definableWords":["days","Jerusalem","people"],"peopleInVerse":[]},"8":{"text":"Jerusalem hath grievously sinned; therefore she is removed: all that honoured her despise her, because they have seen her nakedness: yea, she sigheth, and turneth backward.","ref":"Lamentations 1:8","synthesized":"Jerusalem has sinned greatly; therefore she has become an object of scorn. All who honored her now despise her, for they have seen her nakedness; she herself groans and turns away.","sources":{"KJV":{"text":"Jerusalem hath grievously sinned; therefore she is removed: all that honoured her despise her, because they have seen her nakedness: yea, she sigheth, and turneth backward."},"BSB":{"text":"Jerusalem has sinned greatly; therefore she has become an object of scorn. All who honored her now despise her, for they have seen her nakedness; she herself groans and turns away."}},"definableWords":["Jerusalem"],"peopleInVerse":[]},"9":{"text":"Her filthiness is in her skirts; she remembereth not her last end; therefore she came down wonderfully: she had no comforter. O LORD, behold my affliction: for the enemy hath magnified himself.","ref":"Lamentations 1:9","synthesized":"Her uncleanness stains her skirts; she did not consider her end. Her downfall was astounding; there was no one to comfort her. Look, O LORD, on my affliction, for the enemy has triumphed!","sources":{"KJV":{"text":"Her filthiness is in her skirts; she remembereth not her last end; therefore she came down wonderfully: she had no comforter. O LORD, behold my affliction: for the enemy hath magnified himself."},"BSB":{"text":"Her uncleanness stains her skirts; she did not consider her end. Her downfall was astounding; there was no one to comfort her. Look, O LORD, on my affliction, for the enemy has triumphed!"}},"definableWords":["one","LORD"],"peopleInVerse":[]},"10":{"text":"The adversary hath spread out his hand upon all her pleasant things: for she hath seen that the heathen entered into her sanctuary, whom thou didst command that they should not enter into thy congregation.","ref":"Lamentations 1:10","synthesized":"The adversary has seized all her treasures. For she has seen the nations enter her sanctuary— those You had forbidden to enter Your assembly.","sources":{"KJV":{"text":"The adversary hath spread out his hand upon all her pleasant things: for she hath seen that the heathen entered into her sanctuary, whom thou didst command that they should not enter into thy congregation."},"BSB":{"text":"The adversary has seized all her treasures. For she has seen the nations enter her sanctuary— those You had forbidden to enter Your assembly."}},"definableWords":["nations"],"peopleInVerse":[]},"11":{"text":"All her people sigh, they seek bread; they have given their pleasant things for meat to relieve the soul: see, O LORD, and consider; for I am become vile.","ref":"Lamentations 1:11","synthesized":"All her people groan as they search for bread. They have traded their treasures for food to keep themselves alive. Look, O LORD, and consider, for I have become despised.","sources":{"KJV":{"text":"All her people sigh, they seek bread; they have given their pleasant things for meat to relieve the soul: see, O LORD, and consider; for I am become vile."},"BSB":{"text":"All her people groan as they search for bread. They have traded their treasures for food to keep themselves alive. Look, O LORD, and consider, for I have become despised."}},"definableWords":["people","keep","LORD"],"peopleInVerse":[]},"12":{"text":"Is it nothing to you, all ye that pass by? behold, and see if there be any sorrow like unto my sorrow, which is done unto me, wherewith the LORD hath afflicted me in the day of his fierce anger.","ref":"Lamentations 1:12","synthesized":"Is this nothing to you, all you who pass by? Look around and see! Is there any sorrow like mine, which was inflicted on me, which the LORD made me suffer on the day of His fierce anger?","sources":{"KJV":{"text":"Is it nothing to you, all ye that pass by? behold, and see if there be any sorrow like unto my sorrow, which is done unto me, wherewith the LORD hath afflicted me in the day of his fierce anger."},"BSB":{"text":"Is this nothing to you, all you who pass by? Look around and see! Is there any sorrow like mine, which was inflicted on me, which the LORD made me suffer on the day of His fierce anger?"}},"definableWords":["see","LORD","made","day","anger"],"peopleInVerse":[]},"13":{"text":"From above hath he sent fire into my bones, and it prevaileth against them: he hath spread a net for my feet, he hath turned me back: he hath made me desolate and faint all the day.","ref":"Lamentations 1:13","synthesized":"He sent fire from on high, and it overpowered my bones. He spread a net for my feet and turned me back. He made me desolate, faint all the day long.","sources":{"KJV":{"text":"From above hath he sent fire into my bones, and it prevaileth against them: he hath spread a net for my feet, he hath turned me back: he hath made me desolate and faint all the day."},"BSB":{"text":"He sent fire from on high, and it overpowered my bones. He spread a net for my feet and turned me back. He made me desolate, faint all the day long."}},"definableWords":["bones","made","day"],"peopleInVerse":[]},"14":{"text":"The yoke of my transgressions is bound by his hand: they are wreathed, and come up upon my neck: he hath made my strength to fall, the LORD hath delivered me into their hands, from whom I am not able to rise up.","ref":"Lamentations 1:14","synthesized":"My transgressions are bound into a yoke, knit together by His hand; they are draped over my neck, and the Lord has broken my strength. He has delivered me into the hands of those I cannot withstand.","sources":{"KJV":{"text":"The yoke of my transgressions is bound by his hand: they are wreathed, and come up upon my neck: he hath made my strength to fall, the LORD hath delivered me into their hands, from whom I am not able to rise up."},"BSB":{"text":"My transgressions are bound into a yoke, knit together by His hand; they are draped over my neck, and the Lord has broken my strength. He has delivered me into the hands of those I cannot withstand."}},"definableWords":["Lord"],"peopleInVerse":[]},"15":{"text":"The LORD hath trodden under foot all my mighty men in the midst of me: he hath called an assembly against me to crush my young men: the LORD hath trodden the virgin, the daughter of Judah, as in a winepress.","ref":"Lamentations 1:15","synthesized":"The Lord has rejected all the mighty men in my midst; He has summoned an army against me to crush my young warriors. Like grapes in a winepress, the Lord has trampled the Virgin Daughter of Judah.","sources":{"KJV":{"text":"The LORD hath trodden under foot all my mighty men in the midst of me: he hath called an assembly against me to crush my young men: the LORD hath trodden the virgin, the daughter of Judah, as in a winepress."},"BSB":{"text":"The Lord has rejected all the mighty men in my midst; He has summoned an army against me to crush my young warriors. Like grapes in a winepress, the Lord has trampled the Virgin Daughter of Judah."}},"definableWords":["Lord","mighty","men","daughter","Judah"],"peopleInVerse":[]},"16":{"text":"For these things I weep; mine eye, mine eye runneth down with water, because the comforter that should relieve my soul is far from me: my children are desolate, because the enemy prevailed.","ref":"Lamentations 1:16","synthesized":"For these things I weep; my eyes flow with tears. For there is no one nearby to comfort me, no one to revive my soul. My children are destitute because the enemy has prevailed.","sources":{"KJV":{"text":"For these things I weep; mine eye, mine eye runneth down with water, because the comforter that should relieve my soul is far from me: my children are desolate, because the enemy prevailed."},"BSB":{"text":"For these things I weep; my eyes flow with tears. For there is no one nearby to comfort me, no one to revive my soul. My children are destitute because the enemy has prevailed."}},"definableWords":["one","soul"],"peopleInVerse":[]},"17":{"text":"Zion spreadeth forth her hands, and there is none to comfort her: the LORD hath commanded concerning Jacob, that his adversaries should be round about him: Jerusalem is as a menstruous woman among them.","ref":"Lamentations 1:17","synthesized":"Zion stretches out her hands, but there is no one to comfort her. The LORD has decreed against Jacob that his neighbors become his foes. Jerusalem has become an unclean thing among them.","sources":{"KJV":{"text":"Zion spreadeth forth her hands, and there is none to comfort her: the LORD hath commanded concerning Jacob, that his adversaries should be round about him: Jerusalem is as a menstruous woman among them."},"BSB":{"text":"Zion stretches out her hands, but there is no one to comfort her. The LORD has decreed against Jacob that his neighbors become his foes. Jerusalem has become an unclean thing among them."}},"definableWords":["Zion","one","LORD","Jacob","Jerusalem"],"peopleInVerse":["Jacob"]},"18":{"text":"The LORD is righteous; for I have rebelled against his commandment: hear, I pray you, all people, and behold my sorrow: my virgins and my young men are gone into captivity.","ref":"Lamentations 1:18","synthesized":"The LORD is righteous, for I have rebelled against His command. Listen, all you people; look upon my suffering. My young men and maidens have gone into captivity.","sources":{"KJV":{"text":"The LORD is righteous; for I have rebelled against his commandment: hear, I pray you, all people, and behold my sorrow: my virgins and my young men are gone into captivity."},"BSB":{"text":"The LORD is righteous, for I have rebelled against His command. Listen, all you people; look upon my suffering. My young men and maidens have gone into captivity."}},"definableWords":["LORD","righteous","people","men"],"peopleInVerse":[]},"19":{"text":"I called for my lovers, but they deceived me: my priests and mine elders gave up the ghost in the city, while they sought their meat to relieve their souls.","ref":"Lamentations 1:19","synthesized":"I called out to my lovers, but they have betrayed me. My priests and elders perished in the city while they searched for food to keep themselves alive.","sources":{"KJV":{"text":"I called for my lovers, but they deceived me: my priests and mine elders gave up the ghost in the city, while they sought their meat to relieve their souls."},"BSB":{"text":"I called out to my lovers, but they have betrayed me. My priests and elders perished in the city while they searched for food to keep themselves alive."}},"definableWords":["keep"],"peopleInVerse":[]},"20":{"text":"Behold, O LORD; for I am in distress: my bowels are troubled; mine heart is turned within me; for I have grievously rebelled: abroad the sword bereaveth, at home there is as death.","ref":"Lamentations 1:20","synthesized":"See, O LORD, how distressed I am! I am churning within; my heart is pounding within me, for I have been most rebellious. Outside, the sword bereaves; inside, there is death.","sources":{"KJV":{"text":"Behold, O LORD; for I am in distress: my bowels are troubled; mine heart is turned within me; for I have grievously rebelled: abroad the sword bereaveth, at home there is as death."},"BSB":{"text":"See, O LORD, how distressed I am! I am churning within; my heart is pounding within me, for I have been most rebellious. Outside, the sword bereaves; inside, there is death."}},"definableWords":["see","LORD","heart","death"],"peopleInVerse":[]},"21":{"text":"They have heard that I sigh: there is none to comfort me: all mine enemies have heard of my trouble; they are glad that thou hast done it: thou wilt bring the day that thou hast called, and they shall be like unto me.","ref":"Lamentations 1:21","synthesized":"People have heard my groaning, but there is no one to comfort me. All my enemies have heard of my trouble; they are glad that You have caused it. May You bring the day You have announced, so that they may become like me.","sources":{"KJV":{"text":"They have heard that I sigh: there is none to comfort me: all mine enemies have heard of my trouble; they are glad that thou hast done it: thou wilt bring the day that thou hast called, and they shall be like unto me."},"BSB":{"text":"People have heard my groaning, but there is no one to comfort me. All my enemies have heard of my trouble; they are glad that You have caused it. May You bring the day You have announced, so that they may become like me."}},"definableWords":["people","one","day"],"peopleInVerse":[]},"22":{"text":"Let all their wickedness come before thee; and do unto them, as thou hast done unto me for all my transgressions: for my sighs are many, and my heart is faint.","ref":"Lamentations 1:22","synthesized":"Let all their wickedness come before You, and deal with them as You have dealt with me because of all my transgressions. For my groans are many, and my heart is faint.","sources":{"KJV":{"text":"Let all their wickedness come before thee; and do unto them, as thou hast done unto me for all my transgressions: for my sighs are many, and my heart is faint."},"BSB":{"text":"Let all their wickedness come before You, and deal with them as You have dealt with me because of all my transgressions. For my groans are many, and my heart is faint."}},"definableWords":["heart"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"THE LORD HATH COVERED THE DAUGHTER OF ZION","verses":{"1":{"text":"How hath the LORD covered the daughter of Zion with a cloud in his anger, and cast down from heaven unto the earth the beauty of Israel, and remembered not his footstool in the day of his anger!","ref":"Lamentations 2:1","synthesized":"How the Lord has covered the Daughter of Zion with the cloud of His anger! He has cast the glory of Israel from heaven to earth. He has abandoned His footstool in the day of His anger.","sources":{"KJV":{"text":"How hath the LORD covered the daughter of Zion with a cloud in his anger, and cast down from heaven unto the earth the beauty of Israel, and remembered not his footstool in the day of his anger!"},"BSB":{"text":"How the Lord has covered the Daughter of Zion with the cloud of His anger! He has cast the glory of Israel from heaven to earth. He has abandoned His footstool in the day of His anger."}},"definableWords":["Lord","daughter","Zion","anger","glory","Israel","heaven","earth","day"],"peopleInVerse":[]},"2":{"text":"The LORD hath swallowed up all the habitations of Jacob, and hath not pitied: he hath thrown down in his wrath the strong holds of the daughter of Judah; he hath brought them down to the ground: he hath polluted the kingdom and the princes thereof.","ref":"Lamentations 2:2","synthesized":"Without pity the Lord has swallowed up all the dwellings of Jacob. In His wrath He has demolished the fortified cities of the Daughter of Judah. He brought to the ground and defiled her kingdom and its princes.","sources":{"KJV":{"text":"The LORD hath swallowed up all the habitations of Jacob, and hath not pitied: he hath thrown down in his wrath the strong holds of the daughter of Judah; he hath brought them down to the ground: he hath polluted the kingdom and the princes thereof."},"BSB":{"text":"Without pity the Lord has swallowed up all the dwellings of Jacob. In His wrath He has demolished the fortified cities of the Daughter of Judah. He brought to the ground and defiled her kingdom and its princes."}},"definableWords":["Lord","Jacob","wrath","daughter","Judah","ground","kingdom"],"peopleInVerse":["Jacob"]},"3":{"text":"He hath cut off in his fierce anger all the horn of Israel: he hath drawn back his right hand from before the enemy, and he burned against Jacob like a flaming fire, which devoureth round about.","ref":"Lamentations 2:3","synthesized":"In fierce anger He has cut off every horn of Israel and withdrawn His right hand at the approach of the enemy. He has burned in Jacob like a flaming fire that consumes everything around it.","sources":{"KJV":{"text":"He hath cut off in his fierce anger all the horn of Israel: he hath drawn back his right hand from before the enemy, and he burned against Jacob like a flaming fire, which devoureth round about."},"BSB":{"text":"In fierce anger He has cut off every horn of Israel and withdrawn His right hand at the approach of the enemy. He has burned in Jacob like a flaming fire that consumes everything around it."}},"definableWords":["anger","Israel","Jacob"],"peopleInVerse":["Jacob"]},"4":{"text":"He hath bent his bow like an enemy: he stood with his right hand as an adversary, and slew all that were pleasant to the eye in the tabernacle of the daughter of Zion: he poured out his fury like fire.","ref":"Lamentations 2:4","synthesized":"He has bent His bow like an enemy; His right hand is positioned. Like a foe He has killed all who were pleasing to the eye; He has poured out His wrath like fire on the tent of the Daughter of Zion.","sources":{"KJV":{"text":"He hath bent his bow like an enemy: he stood with his right hand as an adversary, and slew all that were pleasant to the eye in the tabernacle of the daughter of Zion: he poured out his fury like fire."},"BSB":{"text":"He has bent His bow like an enemy; His right hand is positioned. Like a foe He has killed all who were pleasing to the eye; He has poured out His wrath like fire on the tent of the Daughter of Zion."}},"definableWords":["wrath","daughter","Zion"],"peopleInVerse":[]},"5":{"text":"The LORD was as an enemy: he hath swallowed up Israel, he hath swallowed up all her palaces: he hath destroyed his strong holds, and hath increased in the daughter of Judah mourning and lamentation.","ref":"Lamentations 2:5","synthesized":"The Lord is like an enemy; He has swallowed up Israel. He has swallowed up all her palaces and destroyed her strongholds. He has multiplied mourning and lamentation for the Daughter of Judah.","sources":{"KJV":{"text":"The LORD was as an enemy: he hath swallowed up Israel, he hath swallowed up all her palaces: he hath destroyed his strong holds, and hath increased in the daughter of Judah mourning and lamentation."},"BSB":{"text":"The Lord is like an enemy; He has swallowed up Israel. He has swallowed up all her palaces and destroyed her strongholds. He has multiplied mourning and lamentation for the Daughter of Judah."}},"definableWords":["Lord","Israel","daughter","Judah"],"peopleInVerse":[]},"6":{"text":"And he hath violently taken away his tabernacle, as if it were of a garden: he hath destroyed his places of the assembly: the LORD hath caused the solemn feasts and sabbaths to be forgotten in Zion, and hath despised in the indignation of his anger the king and the priest.","ref":"Lamentations 2:6","synthesized":"He has laid waste His tabernacle like a garden booth; He has destroyed His place of meeting. The LORD has made Zion forget her appointed feasts and Sabbaths. In His fierce anger He has despised both king and priest.","sources":{"KJV":{"text":"And he hath violently taken away his tabernacle, as if it were of a garden: he hath destroyed his places of the assembly: the LORD hath caused the solemn feasts and sabbaths to be forgotten in Zion, and hath despised in the indignation of his anger the king and the priest."},"BSB":{"text":"He has laid waste His tabernacle like a garden booth; He has destroyed His place of meeting. The LORD has made Zion forget her appointed feasts and Sabbaths. In His fierce anger He has despised both king and priest."}},"definableWords":["tabernacle","garden","LORD","made","Zion","anger","king","priest"],"peopleInVerse":[]},"7":{"text":"The LORD hath cast off his altar, he hath abhorred his sanctuary, he hath given up into the hand of the enemy the walls of her palaces; they have made a noise in the house of the LORD, as in the day of a solemn feast.","ref":"Lamentations 2:7","synthesized":"The Lord has rejected His altar; He has abandoned His sanctuary; He has delivered the walls of her palaces into the hand of the enemy. They have raised a shout in the house of the LORD as on the day of an appointed feast.","sources":{"KJV":{"text":"The LORD hath cast off his altar, he hath abhorred his sanctuary, he hath given up into the hand of the enemy the walls of her palaces; they have made a noise in the house of the LORD, as in the day of a solemn feast."},"BSB":{"text":"The Lord has rejected His altar; He has abandoned His sanctuary; He has delivered the walls of her palaces into the hand of the enemy. They have raised a shout in the house of the LORD as on the day of an appointed feast."}},"definableWords":["Lord","altar","house","LORD","day"],"peopleInVerse":[]},"8":{"text":"The LORD hath purposed to destroy the wall of the daughter of Zion: he hath stretched out a line, he hath not withdrawn his hand from destroying: therefore he made the rampart and the wall to lament; they languished together.","ref":"Lamentations 2:8","synthesized":"The LORD determined to destroy the wall of the Daughter of Zion. He stretched out a measuring line and did not withdraw His hand from destroying. He made the ramparts and walls lament; together they waste away.","sources":{"KJV":{"text":"The LORD hath purposed to destroy the wall of the daughter of Zion: he hath stretched out a line, he hath not withdrawn his hand from destroying: therefore he made the rampart and the wall to lament; they languished together."},"BSB":{"text":"The LORD determined to destroy the wall of the Daughter of Zion. He stretched out a measuring line and did not withdraw His hand from destroying. He made the ramparts and walls lament; together they waste away."}},"definableWords":["LORD","daughter","Zion","made"],"peopleInVerse":[]},"9":{"text":"Her gates are sunk into the ground; he hath destroyed and broken her bars: her king and her princes are among the Gentiles: the law is no more; her prophets also find no vision from the LORD.","ref":"Lamentations 2:9","synthesized":"Her gates have sunk into the ground; He has destroyed and shattered their bars. Her king and her princes are exiled among the nations, the law is no more, and even her prophets find no vision from the LORD.","sources":{"KJV":{"text":"Her gates are sunk into the ground; he hath destroyed and broken her bars: her king and her princes are among the Gentiles: the law is no more; her prophets also find no vision from the LORD."},"BSB":{"text":"Her gates have sunk into the ground; He has destroyed and shattered their bars. Her king and her princes are exiled among the nations, the law is no more, and even her prophets find no vision from the LORD."}},"definableWords":["ground","king","nations","law","LORD"],"peopleInVerse":[]},"10":{"text":"The elders of the daughter of Zion sit upon the ground, and keep silence: they have cast up dust upon their heads; they have girded themselves with sackcloth: the virgins of Jerusalem hang down their heads to the ground.","ref":"Lamentations 2:10","synthesized":"The elders of the Daughter of Zion sit on the ground in silence. They have thrown dust on their heads and put on sackcloth. The young women of Jerusalem have bowed their heads to the ground.","sources":{"KJV":{"text":"The elders of the daughter of Zion sit upon the ground, and keep silence: they have cast up dust upon their heads; they have girded themselves with sackcloth: the virgins of Jerusalem hang down their heads to the ground."},"BSB":{"text":"The elders of the Daughter of Zion sit on the ground in silence. They have thrown dust on their heads and put on sackcloth. The young women of Jerusalem have bowed their heads to the ground."}},"definableWords":["daughter","Zion","ground","women","Jerusalem"],"peopleInVerse":[]},"11":{"text":"Mine eyes do fail with tears, my bowels are troubled, my liver is poured upon the earth, for the destruction of the daughter of my people; because the children and the sucklings swoon in the streets of the city.","ref":"Lamentations 2:11","synthesized":"My eyes fail from weeping; I am churning within. My heart is poured out in grief over the destruction of the daughter of my people, because children and infants faint in the streets of the city.","sources":{"KJV":{"text":"Mine eyes do fail with tears, my bowels are troubled, my liver is poured upon the earth, for the destruction of the daughter of my people; because the children and the sucklings swoon in the streets of the city."},"BSB":{"text":"My eyes fail from weeping; I am churning within. My heart is poured out in grief over the destruction of the daughter of my people, because children and infants faint in the streets of the city."}},"definableWords":["heart","daughter","people"],"peopleInVerse":[]},"12":{"text":"They say to their mothers, Where is corn and wine? when they swooned as the wounded in the streets of the city, when their soul was poured out into their mothers’ bosom.","ref":"Lamentations 2:12","synthesized":"They cry out to their mothers: “Where is the grain and wine?” as they faint like the wounded in the streets of the city, as their lives fade away in the arms of their mothers.","sources":{"KJV":{"text":"They say to their mothers, Where is corn and wine? when they swooned as the wounded in the streets of the city, when their soul was poured out into their mothers’ bosom."},"BSB":{"text":"They cry out to their mothers: “Where is the grain and wine?” as they faint like the wounded in the streets of the city, as their lives fade away in the arms of their mothers."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"What thing shall I take to witness for thee? what thing shall I liken to thee, O daughter of Jerusalem? what shall I equal to thee, that I may comfort thee, O virgin daughter of Zion? for thy breach is great like the sea: who can heal thee?","ref":"Lamentations 2:13","synthesized":"What can I say for you? To what can I compare you, O Daughter of Jerusalem? To what can I liken you, that I may console you, O Virgin Daughter of Zion? For your wound is as deep as the sea. Who can ever heal you?","sources":{"KJV":{"text":"What thing shall I take to witness for thee? what thing shall I liken to thee, O daughter of Jerusalem? what shall I equal to thee, that I may comfort thee, O virgin daughter of Zion? for thy breach is great like the sea: who can heal thee?"},"BSB":{"text":"What can I say for you? To what can I compare you, O Daughter of Jerusalem? To what can I liken you, that I may console you, O Virgin Daughter of Zion? For your wound is as deep as the sea. Who can ever heal you?"}},"definableWords":["daughter","Jerusalem","Zion","deep","sea","heal"],"peopleInVerse":[]},"14":{"text":"Thy prophets have seen vain and foolish things for thee: and they have not discovered thine iniquity, to turn away thy captivity; but have seen for thee false burdens and causes of banishment.","ref":"Lamentations 2:14","synthesized":"The visions of your prophets were empty and deceptive; they did not expose your guilt to ward off your captivity. The burdens they envisioned for you were empty and misleading.","sources":{"KJV":{"text":"Thy prophets have seen vain and foolish things for thee: and they have not discovered thine iniquity, to turn away thy captivity; but have seen for thee false burdens and causes of banishment."},"BSB":{"text":"The visions of your prophets were empty and deceptive; they did not expose your guilt to ward off your captivity. The burdens they envisioned for you were empty and misleading."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"All that pass by clap their hands at thee; they hiss and wag their head at the daughter of Jerusalem, saying, Is this the city that men call The perfection of beauty, The joy of the whole earth?","ref":"Lamentations 2:15","synthesized":"All who pass by clap their hands at you in scorn. They hiss and shake their heads at the Daughter of Jerusalem: “Is this the city that was called the perfection of beauty, the joy of all the earth?”","sources":{"KJV":{"text":"All that pass by clap their hands at thee; they hiss and wag their head at the daughter of Jerusalem, saying, Is this the city that men call The perfection of beauty, The joy of the whole earth?"},"BSB":{"text":"All who pass by clap their hands at you in scorn. They hiss and shake their heads at the Daughter of Jerusalem: “Is this the city that was called the perfection of beauty, the joy of all the earth?”"}},"definableWords":["daughter","Jerusalem","joy","earth"],"peopleInVerse":[]},"16":{"text":"All thine enemies have opened their mouth against thee: they hiss and gnash the teeth: they say, We have swallowed her up: certainly this is the day that we looked for; we have found, we have seen it.","ref":"Lamentations 2:16","synthesized":"All your enemies open their mouths against you. They hiss and gnash their teeth, saying, “We have swallowed her up. This is the day for which we have waited. We have lived to see it!”","sources":{"KJV":{"text":"All thine enemies have opened their mouth against thee: they hiss and gnash the teeth: they say, We have swallowed her up: certainly this is the day that we looked for; we have found, we have seen it."},"BSB":{"text":"All your enemies open their mouths against you. They hiss and gnash their teeth, saying, “We have swallowed her up. This is the day for which we have waited. We have lived to see it!”"}},"definableWords":["day","see"],"peopleInVerse":[]},"17":{"text":"The LORD hath done that which he had devised; he hath fulfilled his word that he had commanded in the days of old: he hath thrown down, and hath not pitied: and he hath caused thine enemy to rejoice over thee, he hath set up the horn of thine adversaries.","ref":"Lamentations 2:17","synthesized":"The LORD has done what He planned; He has accomplished His decree, which He ordained in days of old; He has overthrown you without pity. He has let the enemy gloat over you and exalted the horn of your foes.","sources":{"KJV":{"text":"The LORD hath done that which he had devised; he hath fulfilled his word that he had commanded in the days of old: he hath thrown down, and hath not pitied: and he hath caused thine enemy to rejoice over thee, he hath set up the horn of thine adversaries."},"BSB":{"text":"The LORD has done what He planned; He has accomplished His decree, which He ordained in days of old; He has overthrown you without pity. He has let the enemy gloat over you and exalted the horn of your foes."}},"definableWords":["LORD","days"],"peopleInVerse":[]},"18":{"text":"Their heart cried unto the LORD, O wall of the daughter of Zion, let tears run down like a river day and night: give thyself no rest; let not the apple of thine eye cease.","ref":"Lamentations 2:18","synthesized":"The hearts of the people cry out to the Lord. O wall of the Daughter of Zion, let your tears run down like a river day and night. Give yourself no relief, and your eyes no rest.","sources":{"KJV":{"text":"Their heart cried unto the LORD, O wall of the daughter of Zion, let tears run down like a river day and night: give thyself no rest; let not the apple of thine eye cease."},"BSB":{"text":"The hearts of the people cry out to the Lord. O wall of the Daughter of Zion, let your tears run down like a river day and night. Give yourself no relief, and your eyes no rest."}},"definableWords":["people","Lord","daughter","Zion","run","day","night","rest"],"peopleInVerse":[]},"19":{"text":"Arise, cry out in the night: in the beginning of the watches pour out thine heart like water before the face of the LORD: lift up thy hands toward him for the life of thy young children, that faint for hunger in the top of every street.","ref":"Lamentations 2:19","synthesized":"Arise, cry out in the night from the first watch of the night. Pour out your heart like water in the presence of the Lord. Lift up your hands to Him for the lives of your children who are fainting from hunger on the corner of every street.","sources":{"KJV":{"text":"Arise, cry out in the night: in the beginning of the watches pour out thine heart like water before the face of the LORD: lift up thy hands toward him for the life of thy young children, that faint for hunger in the top of every street."},"BSB":{"text":"Arise, cry out in the night from the first watch of the night. Pour out your heart like water in the presence of the Lord. Lift up your hands to Him for the lives of your children who are fainting from hunger on the corner of every street."}},"definableWords":["night","heart","water","Lord"],"peopleInVerse":[]},"20":{"text":"Behold, O LORD, and consider to whom thou hast done this. Shall the women eat their fruit, and children of a span long? shall the priest and the prophet be slain in the sanctuary of the Lord?","ref":"Lamentations 2:20","synthesized":"Look, O LORD, and consider: Whom have You ever treated like this? Should women eat their offspring, the infants they have nurtured? Should priests and prophets be killed in the sanctuary of the Lord?","sources":{"KJV":{"text":"Behold, O LORD, and consider to whom thou hast done this. Shall the women eat their fruit, and children of a span long? shall the priest and the prophet be slain in the sanctuary of the Lord?"},"BSB":{"text":"Look, O LORD, and consider: Whom have You ever treated like this? Should women eat their offspring, the infants they have nurtured? Should priests and prophets be killed in the sanctuary of the Lord?"}},"definableWords":["LORD","women","Lord"],"peopleInVerse":[]},"21":{"text":"The young and the old lie on the ground in the streets: my virgins and my young men are fallen by the sword; thou hast slain them in the day of thine anger; thou hast killed, and not pitied.","ref":"Lamentations 2:21","synthesized":"Both young and old lie together in the dust of the streets. My young men and maidens have fallen by the sword. You have slain them in the day of Your anger; You have slaughtered them without compassion.","sources":{"KJV":{"text":"The young and the old lie on the ground in the streets: my virgins and my young men are fallen by the sword; thou hast slain them in the day of thine anger; thou hast killed, and not pitied."},"BSB":{"text":"Both young and old lie together in the dust of the streets. My young men and maidens have fallen by the sword. You have slain them in the day of Your anger; You have slaughtered them without compassion."}},"definableWords":["men","day","anger"],"peopleInVerse":[]},"22":{"text":"Thou hast called as in a solemn day my terrors round about, so that in the day of the LORD’s anger none escaped nor remained: those that I have swaddled and brought up hath mine enemy consumed.","ref":"Lamentations 2:22","synthesized":"You summoned my attackers on every side, as for the day of an appointed feast. In the day of the LORD’s anger no one escaped or survived; my enemy has destroyed those I nurtured and reared.","sources":{"KJV":{"text":"Thou hast called as in a solemn day my terrors round about, so that in the day of the LORD’s anger none escaped nor remained: those that I have swaddled and brought up hath mine enemy consumed."},"BSB":{"text":"You summoned my attackers on every side, as for the day of an appointed feast. In the day of the LORD’s anger no one escaped or survived; my enemy has destroyed those I nurtured and reared."}},"definableWords":["day","LORD","anger","one","or"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"HIS MERCIES ARE NEW EVERY MORNING","verses":{"1":{"text":"I AM the man that hath seen affliction by the rod of his wrath.","ref":"Lamentations 3:1","synthesized":"I am the man who has seen affliction under the rod of God’s wrath.","sources":{"KJV":{"text":"I AM the man that hath seen affliction by the rod of his wrath."},"BSB":{"text":"I am the man who has seen affliction under the rod of God’s wrath."}},"definableWords":["man","God","wrath"],"peopleInVerse":[]},"2":{"text":"He hath led me, and brought me into darkness, but not into light.","ref":"Lamentations 3:2","synthesized":"He has driven me away and made me walk in darkness instead of light.","sources":{"KJV":{"text":"He hath led me, and brought me into darkness, but not into light."},"BSB":{"text":"He has driven me away and made me walk in darkness instead of light."}},"definableWords":["made","walk","darkness","light"],"peopleInVerse":[]},"3":{"text":"Surely against me is he turned; he turneth his hand against me all the day.","ref":"Lamentations 3:3","synthesized":"Indeed, He keeps turning His hand against me all day long.","sources":{"KJV":{"text":"Surely against me is he turned; he turneth his hand against me all the day."},"BSB":{"text":"Indeed, He keeps turning His hand against me all day long."}},"definableWords":["day"],"peopleInVerse":[]},"4":{"text":"My flesh and my skin hath he made old; he hath broken my bones.","ref":"Lamentations 3:4","synthesized":"He has worn away my flesh and skin; He has shattered my bones.","sources":{"KJV":{"text":"My flesh and my skin hath he made old; he hath broken my bones."},"BSB":{"text":"He has worn away my flesh and skin; He has shattered my bones."}},"definableWords":["flesh","bones"],"peopleInVerse":[]},"5":{"text":"He hath builded against me, and compassed me with gall and travail.","ref":"Lamentations 3:5","synthesized":"He has besieged me and surrounded me with bitterness and hardship.","sources":{"KJV":{"text":"He hath builded against me, and compassed me with gall and travail."},"BSB":{"text":"He has besieged me and surrounded me with bitterness and hardship."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"He hath set me in dark places, as they that be dead of old.","ref":"Lamentations 3:6","synthesized":"He has made me dwell in darkness like those dead for ages.","sources":{"KJV":{"text":"He hath set me in dark places, as they that be dead of old."},"BSB":{"text":"He has made me dwell in darkness like those dead for ages."}},"definableWords":["made","darkness"],"peopleInVerse":[]},"7":{"text":"He hath hedged me about, that I cannot get out: he hath made my chain heavy.","ref":"Lamentations 3:7","synthesized":"He has walled me in so I cannot escape; He has weighed me down with chains.","sources":{"KJV":{"text":"He hath hedged me about, that I cannot get out: he hath made my chain heavy."},"BSB":{"text":"He has walled me in so I cannot escape; He has weighed me down with chains."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Also when I cry and shout, he shutteth out my prayer.","ref":"Lamentations 3:8","synthesized":"Even when I cry out and plead for help, He shuts out my prayer.","sources":{"KJV":{"text":"Also when I cry and shout, he shutteth out my prayer."},"BSB":{"text":"Even when I cry out and plead for help, He shuts out my prayer."}},"definableWords":["prayer"],"peopleInVerse":[]},"9":{"text":"He hath inclosed my ways with hewn stone, he hath made my paths crooked.","ref":"Lamentations 3:9","synthesized":"He has barred my ways with cut stones; He has made my paths crooked.","sources":{"KJV":{"text":"He hath inclosed my ways with hewn stone, he hath made my paths crooked."},"BSB":{"text":"He has barred my ways with cut stones; He has made my paths crooked."}},"definableWords":["made"],"peopleInVerse":[]},"10":{"text":"He was unto me as a bear lying in wait, and as a lion in secret places.","ref":"Lamentations 3:10","synthesized":"He is a bear lying in wait, a lion hiding in ambush.","sources":{"KJV":{"text":"He was unto me as a bear lying in wait, and as a lion in secret places."},"BSB":{"text":"He is a bear lying in wait, a lion hiding in ambush."}},"definableWords":["wait","lion"],"peopleInVerse":[]},"11":{"text":"He hath turned aside my ways, and pulled me in pieces: he hath made me desolate.","ref":"Lamentations 3:11","synthesized":"He forced me off my path and tore me to pieces; He left me without help.","sources":{"KJV":{"text":"He hath turned aside my ways, and pulled me in pieces: he hath made me desolate."},"BSB":{"text":"He forced me off my path and tore me to pieces; He left me without help."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"He hath bent his bow, and set me as a mark for the arrow.","ref":"Lamentations 3:12","synthesized":"He bent His bow and set me as the target for His arrow.","sources":{"KJV":{"text":"He hath bent his bow, and set me as a mark for the arrow."},"BSB":{"text":"He bent His bow and set me as the target for His arrow."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"He hath caused the arrows of his quiver to enter into my reins.","ref":"Lamentations 3:13","synthesized":"He pierced my kidneys with His arrows.","sources":{"KJV":{"text":"He hath caused the arrows of his quiver to enter into my reins."},"BSB":{"text":"He pierced my kidneys with His arrows."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"I was a derision to all my people; and their song all the day.","ref":"Lamentations 3:14","synthesized":"I am a laughingstock to all my people; they mock me in song all day long.","sources":{"KJV":{"text":"I was a derision to all my people; and their song all the day."},"BSB":{"text":"I am a laughingstock to all my people; they mock me in song all day long."}},"definableWords":["people","day"],"peopleInVerse":[]},"15":{"text":"He hath filled me with bitterness, he hath made me drunken with wormwood.","ref":"Lamentations 3:15","synthesized":"He has filled me with bitterness; He has intoxicated me with wormwood.","sources":{"KJV":{"text":"He hath filled me with bitterness, he hath made me drunken with wormwood."},"BSB":{"text":"He has filled me with bitterness; He has intoxicated me with wormwood."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"He hath also broken my teeth with gravel stones, he hath covered me with ashes.","ref":"Lamentations 3:16","synthesized":"He has ground my teeth with gravel and trampled me in the dust.","sources":{"KJV":{"text":"He hath also broken my teeth with gravel stones, he hath covered me with ashes."},"BSB":{"text":"He has ground my teeth with gravel and trampled me in the dust."}},"definableWords":["ground"],"peopleInVerse":[]},"17":{"text":"And thou hast removed my soul far off from peace: I forgat prosperity.","ref":"Lamentations 3:17","synthesized":"My soul has been deprived of peace; I have forgotten what prosperity is.","sources":{"KJV":{"text":"And thou hast removed my soul far off from peace: I forgat prosperity."},"BSB":{"text":"My soul has been deprived of peace; I have forgotten what prosperity is."}},"definableWords":["soul","peace"],"peopleInVerse":[]},"18":{"text":"And I said, My strength and my hope is perished from the LORD:","ref":"Lamentations 3:18","synthesized":"So I say, “My strength has perished, along with my hope from the LORD.”","sources":{"KJV":{"text":"And I said, My strength and my hope is perished from the LORD:"},"BSB":{"text":"So I say, “My strength has perished, along with my hope from the LORD.”"}},"definableWords":["hope","LORD"],"peopleInVerse":[]},"19":{"text":"Remembering mine affliction and my misery, the wormwood and the gall.","ref":"Lamentations 3:19","synthesized":"Remember my affliction and wandering, the wormwood and the gall.","sources":{"KJV":{"text":"Remembering mine affliction and my misery, the wormwood and the gall."},"BSB":{"text":"Remember my affliction and wandering, the wormwood and the gall."}},"definableWords":["remember"],"peopleInVerse":[]},"20":{"text":"My soul hath them still in remembrance, and is humbled in me.","ref":"Lamentations 3:20","synthesized":"Surely my soul remembers and is humbled within me.","sources":{"KJV":{"text":"My soul hath them still in remembrance, and is humbled in me."},"BSB":{"text":"Surely my soul remembers and is humbled within me."}},"definableWords":["soul"],"peopleInVerse":[]},"21":{"text":"This I recall to my mind, therefore have I hope.","ref":"Lamentations 3:21","synthesized":"Yet I call this to mind, and therefore I have hope:","sources":{"KJV":{"text":"This I recall to my mind, therefore have I hope."},"BSB":{"text":"Yet I call this to mind, and therefore I have hope:"}},"definableWords":["mind","hope"],"peopleInVerse":[]},"22":{"text":"It is of the LORD’s mercies that we are not consumed, because his compassions fail not.","ref":"Lamentations 3:22","synthesized":"Because of the loving devotion of the LORD we are not consumed, for His mercies never fail.","sources":{"KJV":{"text":"It is of the LORD’s mercies that we are not consumed, because his compassions fail not."},"BSB":{"text":"Because of the loving devotion of the LORD we are not consumed, for His mercies never fail."}},"definableWords":["LORD"],"peopleInVerse":[]},"23":{"text":"They are new every morning: great is thy faithfulness.","ref":"Lamentations 3:23","synthesized":"They are new every morning; great is Your faithfulness!","sources":{"KJV":{"text":"They are new every morning: great is thy faithfulness."},"BSB":{"text":"They are new every morning; great is Your faithfulness!"}},"definableWords":["great"],"peopleInVerse":[]},"24":{"text":"The LORD is my portion, saith my soul; therefore will I hope in him.","ref":"Lamentations 3:24","synthesized":"“The LORD is my portion,” says my soul, “therefore I will hope in Him.”","sources":{"KJV":{"text":"The LORD is my portion, saith my soul; therefore will I hope in him."},"BSB":{"text":"“The LORD is my portion,” says my soul, “therefore I will hope in Him.”"}},"definableWords":["LORD","soul","hope"],"peopleInVerse":[]},"25":{"text":"The LORD is good unto them that wait for him, to the soul that seeketh him.","ref":"Lamentations 3:25","synthesized":"The LORD is good to those who wait for Him, to the soul who seeks Him.","sources":{"KJV":{"text":"The LORD is good unto them that wait for him, to the soul that seeketh him."},"BSB":{"text":"The LORD is good to those who wait for Him, to the soul who seeks Him."}},"definableWords":["LORD","good","wait","soul"],"peopleInVerse":[]},"26":{"text":"It is good that a man should both hope and quietly wait for the salvation of the LORD.","ref":"Lamentations 3:26","synthesized":"It is good to wait quietly for the salvation of the LORD.","sources":{"KJV":{"text":"It is good that a man should both hope and quietly wait for the salvation of the LORD."},"BSB":{"text":"It is good to wait quietly for the salvation of the LORD."}},"definableWords":["good","wait","salvation","LORD"],"peopleInVerse":[]},"27":{"text":"It is good for a man that he bear the yoke in his youth.","ref":"Lamentations 3:27","synthesized":"It is good for a man to bear the yoke while he is still young.","sources":{"KJV":{"text":"It is good for a man that he bear the yoke in his youth."},"BSB":{"text":"It is good for a man to bear the yoke while he is still young."}},"definableWords":["good","man"],"peopleInVerse":[]},"28":{"text":"He sitteth alone and keepeth silence, because he hath borne it upon him.","ref":"Lamentations 3:28","synthesized":"Let him sit alone in silence, for God has disciplined him.","sources":{"KJV":{"text":"He sitteth alone and keepeth silence, because he hath borne it upon him."},"BSB":{"text":"Let him sit alone in silence, for God has disciplined him."}},"definableWords":["God"],"peopleInVerse":[]},"29":{"text":"He putteth his mouth in the dust; if so be there may be hope.","ref":"Lamentations 3:29","synthesized":"Let him bury his face in the dust— perhaps there is still hope.","sources":{"KJV":{"text":"He putteth his mouth in the dust; if so be there may be hope."},"BSB":{"text":"Let him bury his face in the dust— perhaps there is still hope."}},"definableWords":["hope"],"peopleInVerse":[]},"30":{"text":"He giveth his cheek to him that smiteth him: he is filled full with reproach.","ref":"Lamentations 3:30","synthesized":"Let him offer his cheek to the one who would strike him; let him be filled with reproach.","sources":{"KJV":{"text":"He giveth his cheek to him that smiteth him: he is filled full with reproach."},"BSB":{"text":"Let him offer his cheek to the one who would strike him; let him be filled with reproach."}},"definableWords":["one"],"peopleInVerse":[]},"31":{"text":"For the LORD will not cast off for ever:","ref":"Lamentations 3:31","synthesized":"For the Lord will not cast us off forever.","sources":{"KJV":{"text":"For the LORD will not cast off for ever:"},"BSB":{"text":"For the Lord will not cast us off forever."}},"definableWords":["Lord"],"peopleInVerse":[]},"32":{"text":"But though he cause grief, yet will he have compassion according to the multitude of his mercies.","ref":"Lamentations 3:32","synthesized":"Even if He causes grief, He will show compassion according to His abundant loving devotion.","sources":{"KJV":{"text":"But though he cause grief, yet will he have compassion according to the multitude of his mercies."},"BSB":{"text":"Even if He causes grief, He will show compassion according to His abundant loving devotion."}},"definableWords":[],"peopleInVerse":[]},"33":{"text":"For he doth not afflict willingly nor grieve the children of men.","ref":"Lamentations 3:33","synthesized":"For He does not willingly afflict or grieve the sons of men.","sources":{"KJV":{"text":"For he doth not afflict willingly nor grieve the children of men."},"BSB":{"text":"For He does not willingly afflict or grieve the sons of men."}},"definableWords":["or","sons","men"],"peopleInVerse":[]},"34":{"text":"To crush under his feet all the prisoners of the earth,","ref":"Lamentations 3:34","synthesized":"To crush underfoot all the prisoners of the land,","sources":{"KJV":{"text":"To crush under his feet all the prisoners of the earth,"},"BSB":{"text":"To crush underfoot all the prisoners of the land,"}},"definableWords":["land"],"peopleInVerse":[]},"35":{"text":"To turn aside the right of a man before the face of the most High,","ref":"Lamentations 3:35","synthesized":"to deny a man justice before the Most High,","sources":{"KJV":{"text":"To turn aside the right of a man before the face of the most High,"},"BSB":{"text":"to deny a man justice before the Most High,"}},"definableWords":["man","justice"],"peopleInVerse":[]},"36":{"text":"To subvert a man in his cause, the LORD approveth not.","ref":"Lamentations 3:36","synthesized":"to subvert a man in his lawsuit— of these the Lord does not approve.","sources":{"KJV":{"text":"To subvert a man in his cause, the LORD approveth not."},"BSB":{"text":"to subvert a man in his lawsuit— of these the Lord does not approve."}},"definableWords":["man","Lord"],"peopleInVerse":[]},"37":{"text":"Who is he that saith, and it cometh to pass, when the Lord commandeth it not?","ref":"Lamentations 3:37","synthesized":"Who has spoken and it came to pass, unless the Lord has ordained it?","sources":{"KJV":{"text":"Who is he that saith, and it cometh to pass, when the Lord commandeth it not?"},"BSB":{"text":"Who has spoken and it came to pass, unless the Lord has ordained it?"}},"definableWords":["Lord"],"peopleInVerse":[]},"38":{"text":"Out of the mouth of the most High proceedeth not evil and good?","ref":"Lamentations 3:38","synthesized":"Do not both adversity and good come from the mouth of the Most High?","sources":{"KJV":{"text":"Out of the mouth of the most High proceedeth not evil and good?"},"BSB":{"text":"Do not both adversity and good come from the mouth of the Most High?"}},"definableWords":["good"],"peopleInVerse":[]},"39":{"text":"Wherefore doth a living man complain, a man for the punishment of his sins?","ref":"Lamentations 3:39","synthesized":"Why should any mortal man complain, in view of his sins?","sources":{"KJV":{"text":"Wherefore doth a living man complain, a man for the punishment of his sins?"},"BSB":{"text":"Why should any mortal man complain, in view of his sins?"}},"definableWords":["man"],"peopleInVerse":[]},"40":{"text":"Let us search and try our ways, and turn again to the LORD.","ref":"Lamentations 3:40","synthesized":"Let us examine and test our ways, and turn back to the LORD.","sources":{"KJV":{"text":"Let us search and try our ways, and turn again to the LORD."},"BSB":{"text":"Let us examine and test our ways, and turn back to the LORD."}},"definableWords":["LORD"],"peopleInVerse":[]},"41":{"text":"Let us lift up our heart with our hands unto God in the heavens.","ref":"Lamentations 3:41","synthesized":"Let us lift up our hearts and hands to God in heaven:","sources":{"KJV":{"text":"Let us lift up our heart with our hands unto God in the heavens."},"BSB":{"text":"Let us lift up our hearts and hands to God in heaven:"}},"definableWords":["God","heaven"],"peopleInVerse":[]},"42":{"text":"We have transgressed and have rebelled: thou hast not pardoned.","ref":"Lamentations 3:42","synthesized":"“We have sinned and rebelled; You have not forgiven.”","sources":{"KJV":{"text":"We have transgressed and have rebelled: thou hast not pardoned."},"BSB":{"text":"“We have sinned and rebelled; You have not forgiven.”"}},"definableWords":[],"peopleInVerse":[]},"43":{"text":"Thou hast covered with anger, and persecuted us: thou hast slain, thou hast not pitied.","ref":"Lamentations 3:43","synthesized":"You have covered Yourself in anger and pursued us; You have killed without pity.","sources":{"KJV":{"text":"Thou hast covered with anger, and persecuted us: thou hast slain, thou hast not pitied."},"BSB":{"text":"You have covered Yourself in anger and pursued us; You have killed without pity."}},"definableWords":["anger"],"peopleInVerse":[]},"44":{"text":"Thou hast covered thyself with a cloud, that our prayer should not pass through.","ref":"Lamentations 3:44","synthesized":"You have covered Yourself with a cloud that no prayer can pass through.","sources":{"KJV":{"text":"Thou hast covered thyself with a cloud, that our prayer should not pass through."},"BSB":{"text":"You have covered Yourself with a cloud that no prayer can pass through."}},"definableWords":["prayer"],"peopleInVerse":[]},"45":{"text":"Thou hast made us as the offscouring and refuse in the midst of the people.","ref":"Lamentations 3:45","synthesized":"You have made us scum and refuse among the nations.","sources":{"KJV":{"text":"Thou hast made us as the offscouring and refuse in the midst of the people."},"BSB":{"text":"You have made us scum and refuse among the nations."}},"definableWords":["made","nations"],"peopleInVerse":[]},"46":{"text":"All our enemies have opened their mouths against us.","ref":"Lamentations 3:46","synthesized":"All our enemies open their mouths against us.","sources":{"KJV":{"text":"All our enemies have opened their mouths against us."},"BSB":{"text":"All our enemies open their mouths against us."}},"definableWords":[],"peopleInVerse":[]},"47":{"text":"Fear and a snare is come upon us, desolation and destruction.","ref":"Lamentations 3:47","synthesized":"Panic and pitfall have come upon us— devastation and destruction.","sources":{"KJV":{"text":"Fear and a snare is come upon us, desolation and destruction."},"BSB":{"text":"Panic and pitfall have come upon us— devastation and destruction."}},"definableWords":[],"peopleInVerse":[]},"48":{"text":"Mine eye runneth down with rivers of water for the destruction of the daughter of my people.","ref":"Lamentations 3:48","synthesized":"Streams of tears flow from my eyes over the destruction of the daughter of my people.","sources":{"KJV":{"text":"Mine eye runneth down with rivers of water for the destruction of the daughter of my people."},"BSB":{"text":"Streams of tears flow from my eyes over the destruction of the daughter of my people."}},"definableWords":["daughter","people"],"peopleInVerse":[]},"49":{"text":"Mine eye trickleth down, and ceaseth not, without any intermission,","ref":"Lamentations 3:49","synthesized":"My eyes overflow unceasingly, without relief,","sources":{"KJV":{"text":"Mine eye trickleth down, and ceaseth not, without any intermission,"},"BSB":{"text":"My eyes overflow unceasingly, without relief,"}},"definableWords":[],"peopleInVerse":[]},"50":{"text":"Till the LORD look down, and behold from heaven.","ref":"Lamentations 3:50","synthesized":"until the LORD looks down from heaven and sees.","sources":{"KJV":{"text":"Till the LORD look down, and behold from heaven."},"BSB":{"text":"until the LORD looks down from heaven and sees."}},"definableWords":["LORD","heaven"],"peopleInVerse":[]},"51":{"text":"Mine eye affecteth mine heart because of all the daughters of my city.","ref":"Lamentations 3:51","synthesized":"My eyes bring grief to my soul because of all the daughters of my city.","sources":{"KJV":{"text":"Mine eye affecteth mine heart because of all the daughters of my city."},"BSB":{"text":"My eyes bring grief to my soul because of all the daughters of my city."}},"definableWords":["soul","daughters"],"peopleInVerse":[]},"52":{"text":"Mine enemies chased me sore, like a bird, without cause.","ref":"Lamentations 3:52","synthesized":"Without cause my enemies hunted me like a bird.","sources":{"KJV":{"text":"Mine enemies chased me sore, like a bird, without cause."},"BSB":{"text":"Without cause my enemies hunted me like a bird."}},"definableWords":["bird"],"peopleInVerse":[]},"53":{"text":"They have cut off my life in the dungeon, and cast a stone upon me.","ref":"Lamentations 3:53","synthesized":"They dropped me alive into a pit and cast stones upon me.","sources":{"KJV":{"text":"They have cut off my life in the dungeon, and cast a stone upon me."},"BSB":{"text":"They dropped me alive into a pit and cast stones upon me."}},"definableWords":[],"peopleInVerse":[]},"54":{"text":"Waters flowed over mine head; then I said, I am cut off.","ref":"Lamentations 3:54","synthesized":"The waters flowed over my head, and I thought I was going to die.","sources":{"KJV":{"text":"Waters flowed over mine head; then I said, I am cut off."},"BSB":{"text":"The waters flowed over my head, and I thought I was going to die."}},"definableWords":["waters","die"],"peopleInVerse":[]},"55":{"text":"I called upon thy name, O LORD, out of the low dungeon.","ref":"Lamentations 3:55","synthesized":"I called on Your name, O LORD, out of the depths of the Pit.","sources":{"KJV":{"text":"I called upon thy name, O LORD, out of the low dungeon."},"BSB":{"text":"I called on Your name, O LORD, out of the depths of the Pit."}},"definableWords":["name","LORD"],"peopleInVerse":[]},"56":{"text":"Thou hast heard my voice: hide not thine ear at my breathing, at my cry.","ref":"Lamentations 3:56","synthesized":"You heard my plea: “Do not ignore my cry for relief.”","sources":{"KJV":{"text":"Thou hast heard my voice: hide not thine ear at my breathing, at my cry."},"BSB":{"text":"You heard my plea: “Do not ignore my cry for relief.”"}},"definableWords":[],"peopleInVerse":[]},"57":{"text":"Thou drewest near in the day that I called upon thee: thou saidst, Fear not.","ref":"Lamentations 3:57","synthesized":"You drew near when I called on You; You said, “Do not be afraid.”","sources":{"KJV":{"text":"Thou drewest near in the day that I called upon thee: thou saidst, Fear not."},"BSB":{"text":"You drew near when I called on You; You said, “Do not be afraid.”"}},"definableWords":[],"peopleInVerse":[]},"58":{"text":"O LORD, thou hast pleaded the causes of my soul; thou hast redeemed my life.","ref":"Lamentations 3:58","synthesized":"You defend my cause, O Lord; You redeem my life.","sources":{"KJV":{"text":"O LORD, thou hast pleaded the causes of my soul; thou hast redeemed my life."},"BSB":{"text":"You defend my cause, O Lord; You redeem my life."}},"definableWords":["Lord","life"],"peopleInVerse":[]},"59":{"text":"O LORD, thou hast seen my wrong: judge thou my cause.","ref":"Lamentations 3:59","synthesized":"You have seen, O LORD, the wrong done to me; vindicate my cause!","sources":{"KJV":{"text":"O LORD, thou hast seen my wrong: judge thou my cause."},"BSB":{"text":"You have seen, O LORD, the wrong done to me; vindicate my cause!"}},"definableWords":["LORD"],"peopleInVerse":[]},"60":{"text":"Thou hast seen all their vengeance and all their imaginations against me.","ref":"Lamentations 3:60","synthesized":"You have seen all their malice, all their plots against me.","sources":{"KJV":{"text":"Thou hast seen all their vengeance and all their imaginations against me."},"BSB":{"text":"You have seen all their malice, all their plots against me."}},"definableWords":[],"peopleInVerse":[]},"61":{"text":"Thou hast heard their reproach, O LORD, and all their imaginations against me;","ref":"Lamentations 3:61","synthesized":"O LORD, You have heard their insults, all their plots against me—","sources":{"KJV":{"text":"Thou hast heard their reproach, O LORD, and all their imaginations against me;"},"BSB":{"text":"O LORD, You have heard their insults, all their plots against me—"}},"definableWords":["LORD"],"peopleInVerse":[]},"62":{"text":"The lips of those that rose up against me, and their device against me all the day.","ref":"Lamentations 3:62","synthesized":"the slander and murmuring of my assailants against me all day long.","sources":{"KJV":{"text":"The lips of those that rose up against me, and their device against me all the day."},"BSB":{"text":"the slander and murmuring of my assailants against me all day long."}},"definableWords":["day"],"peopleInVerse":[]},"63":{"text":"Behold their sitting down, and their rising up; I am their musick.","ref":"Lamentations 3:63","synthesized":"When they sit and when they rise, see how they mock me in song.","sources":{"KJV":{"text":"Behold their sitting down, and their rising up; I am their musick."},"BSB":{"text":"When they sit and when they rise, see how they mock me in song."}},"definableWords":["see"],"peopleInVerse":[]},"64":{"text":"Render unto them a recompence, O LORD, according to the work of their hands.","ref":"Lamentations 3:64","synthesized":"You will pay them back what they deserve, O LORD, according to the work of their hands.","sources":{"KJV":{"text":"Render unto them a recompence, O LORD, according to the work of their hands."},"BSB":{"text":"You will pay them back what they deserve, O LORD, according to the work of their hands."}},"definableWords":["LORD","work"],"peopleInVerse":[]},"65":{"text":"Give them sorrow of heart, thy curse unto them.","ref":"Lamentations 3:65","synthesized":"Put a veil of anguish over their hearts; may Your curse be upon them!","sources":{"KJV":{"text":"Give them sorrow of heart, thy curse unto them."},"BSB":{"text":"Put a veil of anguish over their hearts; may Your curse be upon them!"}},"definableWords":["curse"],"peopleInVerse":[]},"66":{"text":"Persecute and destroy them in anger from under the heavens of the LORD.","ref":"Lamentations 3:66","synthesized":"You will pursue them in anger and exterminate them from under Your heavens, O LORD.","sources":{"KJV":{"text":"Persecute and destroy them in anger from under the heavens of the LORD."},"BSB":{"text":"You will pursue them in anger and exterminate them from under Your heavens, O LORD."}},"definableWords":["anger","heavens","LORD"],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"FROM GOLD TO BROKEN POTTERY","verses":{"1":{"text":"How is the gold become dim! how is the most fine gold changed! the stones of the sanctuary are poured out in the top of every street.","ref":"Lamentations 4:1","synthesized":"How the gold has become tarnished, the pure gold has become dull! The gems of the temple lie scattered on every street corner.","sources":{"KJV":{"text":"How is the gold become dim! how is the most fine gold changed! the stones of the sanctuary are poured out in the top of every street."},"BSB":{"text":"How the gold has become tarnished, the pure gold has become dull! The gems of the temple lie scattered on every street corner."}},"definableWords":["temple"],"peopleInVerse":[]},"2":{"text":"The precious sons of Zion, comparable to fine gold, how are they esteemed as earthen pitchers, the work of the hands of the potter!","ref":"Lamentations 4:2","synthesized":"How the precious sons of Zion, once worth their weight in pure gold, are now esteemed as jars of clay, the work of a potter’s hands!","sources":{"KJV":{"text":"The precious sons of Zion, comparable to fine gold, how are they esteemed as earthen pitchers, the work of the hands of the potter!"},"BSB":{"text":"How the precious sons of Zion, once worth their weight in pure gold, are now esteemed as jars of clay, the work of a potter’s hands!"}},"definableWords":["sons","Zion","work"],"peopleInVerse":[]},"3":{"text":"Even the sea monsters draw out the breast, they give suck to their young ones: the daughter of my people is become cruel, like the ostriches in the wilderness.","ref":"Lamentations 4:3","synthesized":"Even jackals offer their breasts to nurse their young, but the daughter of my people has become cruel, like an ostrich in the wilderness.","sources":{"KJV":{"text":"Even the sea monsters draw out the breast, they give suck to their young ones: the daughter of my people is become cruel, like the ostriches in the wilderness."},"BSB":{"text":"Even jackals offer their breasts to nurse their young, but the daughter of my people has become cruel, like an ostrich in the wilderness."}},"definableWords":["daughter","people"],"peopleInVerse":[]},"4":{"text":"The tongue of the sucking child cleaveth to the roof of his mouth for thirst: the young children ask bread, and no man breaketh it unto them.","ref":"Lamentations 4:4","synthesized":"The nursing infant’s tongue clings in thirst to the roof of his mouth. Little children beg for bread, but no one gives them any.","sources":{"KJV":{"text":"The tongue of the sucking child cleaveth to the roof of his mouth for thirst: the young children ask bread, and no man breaketh it unto them."},"BSB":{"text":"The nursing infant’s tongue clings in thirst to the roof of his mouth. Little children beg for bread, but no one gives them any."}},"definableWords":["one"],"peopleInVerse":[]},"5":{"text":"They that did feed delicately are desolate in the streets: they that were brought up in scarlet embrace dunghills.","ref":"Lamentations 4:5","synthesized":"Those who once ate delicacies are destitute in the streets; those brought up in crimson huddle in ash heaps.","sources":{"KJV":{"text":"They that did feed delicately are desolate in the streets: they that were brought up in scarlet embrace dunghills."},"BSB":{"text":"Those who once ate delicacies are destitute in the streets; those brought up in crimson huddle in ash heaps."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"For the punishment of the iniquity of the daughter of my people is greater than the punishment of the sin of Sodom, that was overthrown as in a moment, and no hands stayed on her.","ref":"Lamentations 4:6","synthesized":"The punishment of the daughter of my people is greater than that of Sodom, which was overthrown in an instant without a hand turned to help her.","sources":{"KJV":{"text":"For the punishment of the iniquity of the daughter of my people is greater than the punishment of the sin of Sodom, that was overthrown as in a moment, and no hands stayed on her."},"BSB":{"text":"The punishment of the daughter of my people is greater than that of Sodom, which was overthrown in an instant without a hand turned to help her."}},"definableWords":["daughter","people","Sodom"],"peopleInVerse":[]},"7":{"text":"Her Nazarites were purer than snow, they were whiter than milk, they were more ruddy in body than rubies, their polishing was of sapphire:","ref":"Lamentations 4:7","synthesized":"Her dignitaries were brighter than snow, whiter than milk; their bodies were more ruddy than rubies, their appearance like sapphires.","sources":{"KJV":{"text":"Her Nazarites were purer than snow, they were whiter than milk, they were more ruddy in body than rubies, their polishing was of sapphire:"},"BSB":{"text":"Her dignitaries were brighter than snow, whiter than milk; their bodies were more ruddy than rubies, their appearance like sapphires."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Their visage is blacker than a coal; they are not known in the streets: their skin cleaveth to their bones; it is withered, it is become like a stick.","ref":"Lamentations 4:8","synthesized":"But now their appearance is blacker than soot; they are not recognized in the streets. Their skin has shriveled on their bones; it has become as dry as a stick.","sources":{"KJV":{"text":"Their visage is blacker than a coal; they are not known in the streets: their skin cleaveth to their bones; it is withered, it is become like a stick."},"BSB":{"text":"But now their appearance is blacker than soot; they are not recognized in the streets. Their skin has shriveled on their bones; it has become as dry as a stick."}},"definableWords":["bones"],"peopleInVerse":[]},"9":{"text":"They that be slain with the sword are better than they that be slain with hunger: for these pine away, stricken through for want of the fruits of the field.","ref":"Lamentations 4:9","synthesized":"Those slain by the sword are better off than those who die of hunger, who waste away, pierced with pain because the fields lack produce.","sources":{"KJV":{"text":"They that be slain with the sword are better than they that be slain with hunger: for these pine away, stricken through for want of the fruits of the field."},"BSB":{"text":"Those slain by the sword are better off than those who die of hunger, who waste away, pierced with pain because the fields lack produce."}},"definableWords":["die"],"peopleInVerse":[]},"10":{"text":"The hands of the pitiful women have sodden their own children: they were their meat in the destruction of the daughter of my people.","ref":"Lamentations 4:10","synthesized":"The hands of compassionate women have cooked their own children, who became their food in the destruction of the daughter of my people.","sources":{"KJV":{"text":"The hands of the pitiful women have sodden their own children: they were their meat in the destruction of the daughter of my people."},"BSB":{"text":"The hands of compassionate women have cooked their own children, who became their food in the destruction of the daughter of my people."}},"definableWords":["women","daughter","people"],"peopleInVerse":[]},"11":{"text":"The LORD hath accomplished his fury; he hath poured out his fierce anger, and hath kindled a fire in Zion, and it hath devoured the foundations thereof.","ref":"Lamentations 4:11","synthesized":"The LORD has exhausted His wrath; He has poured out His fierce anger; He has kindled a fire in Zion, and it has consumed her foundations.","sources":{"KJV":{"text":"The LORD hath accomplished his fury; he hath poured out his fierce anger, and hath kindled a fire in Zion, and it hath devoured the foundations thereof."},"BSB":{"text":"The LORD has exhausted His wrath; He has poured out His fierce anger; He has kindled a fire in Zion, and it has consumed her foundations."}},"definableWords":["LORD","wrath","anger","Zion"],"peopleInVerse":[]},"12":{"text":"The kings of the earth, and all the inhabitants of the world, would not have believed that the adversary and the enemy should have entered into the gates of Jerusalem.","ref":"Lamentations 4:12","synthesized":"The kings of the earth did not believe, nor any people of the world, that an enemy or a foe could enter the gates of Jerusalem.","sources":{"KJV":{"text":"The kings of the earth, and all the inhabitants of the world, would not have believed that the adversary and the enemy should have entered into the gates of Jerusalem."},"BSB":{"text":"The kings of the earth did not believe, nor any people of the world, that an enemy or a foe could enter the gates of Jerusalem."}},"definableWords":["kings","earth","people","or","Jerusalem"],"peopleInVerse":[]},"13":{"text":"For the sins of her prophets, and the iniquities of her priests, that have shed the blood of the just in the midst of her,","ref":"Lamentations 4:13","synthesized":"But this was for the sins of her prophets and the guilt of her priests, who shed the blood of the righteous in her midst.","sources":{"KJV":{"text":"For the sins of her prophets, and the iniquities of her priests, that have shed the blood of the just in the midst of her,"},"BSB":{"text":"But this was for the sins of her prophets and the guilt of her priests, who shed the blood of the righteous in her midst."}},"definableWords":["blood","righteous"],"peopleInVerse":[]},"14":{"text":"They have wandered as blind men in the streets, they have polluted themselves with blood, so that men could not touch their garments.","ref":"Lamentations 4:14","synthesized":"They wandered blind in the streets, defiled by this blood, so that no one dared to touch their garments.","sources":{"KJV":{"text":"They have wandered as blind men in the streets, they have polluted themselves with blood, so that men could not touch their garments."},"BSB":{"text":"They wandered blind in the streets, defiled by this blood, so that no one dared to touch their garments."}},"definableWords":["blood","one"],"peopleInVerse":[]},"15":{"text":"They cried unto them, Depart ye; it is unclean; depart, depart, touch not: when they fled away and wandered, they said among the heathen, They shall no more sojourn there.","ref":"Lamentations 4:15","synthesized":"“Go away! Unclean!” men shouted at them. “Away, away! Do not touch us!” So they fled and wandered. Among the nations it was said, “They can stay here no longer.”","sources":{"KJV":{"text":"They cried unto them, Depart ye; it is unclean; depart, depart, touch not: when they fled away and wandered, they said among the heathen, They shall no more sojourn there."},"BSB":{"text":"“Go away! Unclean!” men shouted at them. “Away, away! Do not touch us!” So they fled and wandered. Among the nations it was said, “They can stay here no longer.”"}},"definableWords":["men","nations"],"peopleInVerse":[]},"16":{"text":"The anger of the LORD hath divided them; he will no more regard them: they respected not the persons of the priests, they favoured not the elders.","ref":"Lamentations 4:16","synthesized":"The presence of the LORD has scattered them; He regards them no more. The priests are shown no honor; the elders find no favor.","sources":{"KJV":{"text":"The anger of the LORD hath divided them; he will no more regard them: they respected not the persons of the priests, they favoured not the elders."},"BSB":{"text":"The presence of the LORD has scattered them; He regards them no more. The priests are shown no honor; the elders find no favor."}},"definableWords":["LORD"],"peopleInVerse":[]},"17":{"text":"As for us, our eyes as yet failed for our vain help: in our watching we have watched for a nation that could not save us.","ref":"Lamentations 4:17","synthesized":"All the while our eyes were failing as we looked in vain for help. We watched from our towers for a nation that could not save us.","sources":{"KJV":{"text":"As for us, our eyes as yet failed for our vain help: in our watching we have watched for a nation that could not save us."},"BSB":{"text":"All the while our eyes were failing as we looked in vain for help. We watched from our towers for a nation that could not save us."}},"definableWords":["nation"],"peopleInVerse":[]},"18":{"text":"They hunt our steps, that we cannot go in our streets: our end is near, our days are fulfilled; for our end is come.","ref":"Lamentations 4:18","synthesized":"They stalked our every step, so that we could not walk in our streets. Our end drew near, our time ran out, for our end had come!","sources":{"KJV":{"text":"They hunt our steps, that we cannot go in our streets: our end is near, our days are fulfilled; for our end is come."},"BSB":{"text":"They stalked our every step, so that we could not walk in our streets. Our end drew near, our time ran out, for our end had come!"}},"definableWords":["walk"],"peopleInVerse":[]},"19":{"text":"Our persecutors are swifter than the eagles of the heaven: they pursued us upon the mountains, they laid wait for us in the wilderness.","ref":"Lamentations 4:19","synthesized":"Those who chased us were swifter than the eagles in the sky; they pursued us over the mountains and ambushed us in the wilderness.","sources":{"KJV":{"text":"Our persecutors are swifter than the eagles of the heaven: they pursued us upon the mountains, they laid wait for us in the wilderness."},"BSB":{"text":"Those who chased us were swifter than the eagles in the sky; they pursued us over the mountains and ambushed us in the wilderness."}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"The breath of our nostrils, the anointed of the LORD, was taken in their pits, of whom we said, Under his shadow we shall live among the heathen.","ref":"Lamentations 4:20","synthesized":"The LORD’s anointed, the breath of our life, was captured in their pits. We had said of him, “Under his shadow we will live among the nations.”","sources":{"KJV":{"text":"The breath of our nostrils, the anointed of the LORD, was taken in their pits, of whom we said, Under his shadow we shall live among the heathen."},"BSB":{"text":"The LORD’s anointed, the breath of our life, was captured in their pits. We had said of him, “Under his shadow we will live among the nations.”"}},"definableWords":["LORD","breath","life","live","nations"],"peopleInVerse":[]},"21":{"text":"Rejoice and be glad, O daughter of Edom, that dwellest in the land of Uz; the cup also shall pass through unto thee: thou shalt be drunken, and shalt make thyself naked.","ref":"Lamentations 4:21","synthesized":"So rejoice and be glad, O Daughter of Edom, you who dwell in the land of Uz. Yet the cup will pass to you as well; you will get drunk and expose yourself.","sources":{"KJV":{"text":"Rejoice and be glad, O daughter of Edom, that dwellest in the land of Uz; the cup also shall pass through unto thee: thou shalt be drunken, and shalt make thyself naked."},"BSB":{"text":"So rejoice and be glad, O Daughter of Edom, you who dwell in the land of Uz. Yet the cup will pass to you as well; you will get drunk and expose yourself."}},"definableWords":["daughter","Edom","land"],"peopleInVerse":[]},"22":{"text":"The punishment of thine iniquity is accomplished, O daughter of Zion; he will no more carry thee away into captivity: he will visit thine iniquity, O daughter of Edom; he will discover thy sins.","ref":"Lamentations 4:22","synthesized":"O Daughter of Zion, your punishment is complete; He will not prolong your exile. But He will punish your iniquity, O Daughter of Edom; He will expose your sins.","sources":{"KJV":{"text":"The punishment of thine iniquity is accomplished, O daughter of Zion; he will no more carry thee away into captivity: he will visit thine iniquity, O daughter of Edom; he will discover thy sins."},"BSB":{"text":"O Daughter of Zion, your punishment is complete; He will not prolong your exile. But He will punish your iniquity, O Daughter of Edom; He will expose your sins."}},"definableWords":["daughter","Zion","iniquity","Edom"],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"REMEMBER, O LORD","verses":{"1":{"text":"Remember, O LORD, what is come upon us: consider, and behold our reproach.","ref":"Lamentations 5:1","synthesized":"Remember, O LORD, what has happened to us. Look and see our disgrace!","sources":{"KJV":{"text":"Remember, O LORD, what is come upon us: consider, and behold our reproach."},"BSB":{"text":"Remember, O LORD, what has happened to us. Look and see our disgrace!"}},"definableWords":["remember","LORD","see"],"peopleInVerse":[]},"2":{"text":"Our inheritance is turned to strangers, our houses to aliens.","ref":"Lamentations 5:2","synthesized":"Our inheritance has been turned over to strangers, our houses to foreigners.","sources":{"KJV":{"text":"Our inheritance is turned to strangers, our houses to aliens."},"BSB":{"text":"Our inheritance has been turned over to strangers, our houses to foreigners."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"We are orphans and fatherless, our mothers are as widows.","ref":"Lamentations 5:3","synthesized":"We have become fatherless orphans; our mothers are widows.","sources":{"KJV":{"text":"We are orphans and fatherless, our mothers are as widows."},"BSB":{"text":"We have become fatherless orphans; our mothers are widows."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"We have drunken our water for money; our wood is sold unto us.","ref":"Lamentations 5:4","synthesized":"We must buy the water we drink; our wood comes at a price.","sources":{"KJV":{"text":"We have drunken our water for money; our wood is sold unto us."},"BSB":{"text":"We must buy the water we drink; our wood comes at a price."}},"definableWords":["water"],"peopleInVerse":[]},"5":{"text":"Our necks are under persecution: we labour, and have no rest.","ref":"Lamentations 5:5","synthesized":"We are closely pursued; we are weary and find no rest.","sources":{"KJV":{"text":"Our necks are under persecution: we labour, and have no rest."},"BSB":{"text":"We are closely pursued; we are weary and find no rest."}},"definableWords":["rest"],"peopleInVerse":[]},"6":{"text":"We have given the hand to the Egyptians, and to the Assyrians, to be satisfied with bread.","ref":"Lamentations 5:6","synthesized":"We submitted to Egypt and Assyria to get enough bread.","sources":{"KJV":{"text":"We have given the hand to the Egyptians, and to the Assyrians, to be satisfied with bread."},"BSB":{"text":"We submitted to Egypt and Assyria to get enough bread."}},"definableWords":["Egypt"],"peopleInVerse":[]},"7":{"text":"Our fathers have sinned, and are not; and we have borne their iniquities.","ref":"Lamentations 5:7","synthesized":"Our fathers sinned and are no more, but we bear their punishment.","sources":{"KJV":{"text":"Our fathers have sinned, and are not; and we have borne their iniquities."},"BSB":{"text":"Our fathers sinned and are no more, but we bear their punishment."}},"definableWords":["fathers"],"peopleInVerse":[]},"8":{"text":"Servants have ruled over us: there is none that doth deliver us out of their hand.","ref":"Lamentations 5:8","synthesized":"Slaves rule over us; there is no one to deliver us from their hands.","sources":{"KJV":{"text":"Servants have ruled over us: there is none that doth deliver us out of their hand."},"BSB":{"text":"Slaves rule over us; there is no one to deliver us from their hands."}},"definableWords":["rule","one","deliver"],"peopleInVerse":[]},"9":{"text":"We gat our bread with the peril of our lives because of the sword of the wilderness.","ref":"Lamentations 5:9","synthesized":"We get our bread at the risk of our lives because of the sword in the wilderness.","sources":{"KJV":{"text":"We gat our bread with the peril of our lives because of the sword of the wilderness."},"BSB":{"text":"We get our bread at the risk of our lives because of the sword in the wilderness."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"Our skin was black like an oven because of the terrible famine.","ref":"Lamentations 5:10","synthesized":"Our skin is as hot as an oven with fever from our hunger.","sources":{"KJV":{"text":"Our skin was black like an oven because of the terrible famine."},"BSB":{"text":"Our skin is as hot as an oven with fever from our hunger."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"They ravished the women in Zion, and the maids in the cities of Judah.","ref":"Lamentations 5:11","synthesized":"Women have been ravished in Zion, virgins in the cities of Judah.","sources":{"KJV":{"text":"They ravished the women in Zion, and the maids in the cities of Judah."},"BSB":{"text":"Women have been ravished in Zion, virgins in the cities of Judah."}},"definableWords":["women","Zion","Judah"],"peopleInVerse":[]},"12":{"text":"Princes are hanged up by their hand: the faces of elders were not honoured.","ref":"Lamentations 5:12","synthesized":"Princes have been hung up by their hands; elders receive no respect.","sources":{"KJV":{"text":"Princes are hanged up by their hand: the faces of elders were not honoured."},"BSB":{"text":"Princes have been hung up by their hands; elders receive no respect."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"They took the young men to grind, and the children fell under the wood.","ref":"Lamentations 5:13","synthesized":"Young men toil at millstones; boys stagger under loads of wood.","sources":{"KJV":{"text":"They took the young men to grind, and the children fell under the wood."},"BSB":{"text":"Young men toil at millstones; boys stagger under loads of wood."}},"definableWords":["men"],"peopleInVerse":[]},"14":{"text":"The elders have ceased from the gate, the young men from their musick.","ref":"Lamentations 5:14","synthesized":"The elders have left the city gate; the young men have stopped their music.","sources":{"KJV":{"text":"The elders have ceased from the gate, the young men from their musick."},"BSB":{"text":"The elders have left the city gate; the young men have stopped their music."}},"definableWords":["men"],"peopleInVerse":[]},"15":{"text":"The joy of our heart is ceased; our dance is turned into mourning.","ref":"Lamentations 5:15","synthesized":"Joy has left our hearts; our dancing has turned to mourning.","sources":{"KJV":{"text":"The joy of our heart is ceased; our dance is turned into mourning."},"BSB":{"text":"Joy has left our hearts; our dancing has turned to mourning."}},"definableWords":["joy"],"peopleInVerse":[]},"16":{"text":"The crown is fallen from our head: woe unto us, that we have sinned!","ref":"Lamentations 5:16","synthesized":"The crown has fallen from our head. Woe to us, for we have sinned!","sources":{"KJV":{"text":"The crown is fallen from our head: woe unto us, that we have sinned!"},"BSB":{"text":"The crown has fallen from our head. Woe to us, for we have sinned!"}},"definableWords":["crown"],"peopleInVerse":[]},"17":{"text":"For this our heart is faint; for these things our eyes are dim.","ref":"Lamentations 5:17","synthesized":"Because of this, our hearts are faint; because of these, our eyes grow dim—","sources":{"KJV":{"text":"For this our heart is faint; for these things our eyes are dim."},"BSB":{"text":"Because of this, our hearts are faint; because of these, our eyes grow dim—"}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"Because of the mountain of Zion, which is desolate, the foxes walk upon it.","ref":"Lamentations 5:18","synthesized":"because of Mount Zion, which lies desolate, patrolled by foxes.","sources":{"KJV":{"text":"Because of the mountain of Zion, which is desolate, the foxes walk upon it."},"BSB":{"text":"because of Mount Zion, which lies desolate, patrolled by foxes."}},"definableWords":["Zion"],"peopleInVerse":[]},"19":{"text":"Thou, O LORD, remainest for ever; thy throne from generation to generation.","ref":"Lamentations 5:19","synthesized":"You, O LORD, reign forever; Your throne endures from generation to generation.","sources":{"KJV":{"text":"Thou, O LORD, remainest for ever; thy throne from generation to generation."},"BSB":{"text":"You, O LORD, reign forever; Your throne endures from generation to generation."}},"definableWords":["LORD","reign","throne"],"peopleInVerse":[]},"20":{"text":"Wherefore dost thou forget us for ever, and forsake us so long time?","ref":"Lamentations 5:20","synthesized":"Why have You forgotten us forever? Why have You forsaken us for so long?","sources":{"KJV":{"text":"Wherefore dost thou forget us for ever, and forsake us so long time?"},"BSB":{"text":"Why have You forgotten us forever? Why have You forsaken us for so long?"}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"Turn thou us unto thee, O LORD, and we shall be turned; renew our days as of old.","ref":"Lamentations 5:21","synthesized":"Restore us to Yourself, O LORD, so we may return; renew our days as of old,","sources":{"KJV":{"text":"Turn thou us unto thee, O LORD, and we shall be turned; renew our days as of old."},"BSB":{"text":"Restore us to Yourself, O LORD, so we may return; renew our days as of old,"}},"definableWords":["LORD","days"],"peopleInVerse":[]},"22":{"text":"But thou hast utterly rejected us; thou art very wroth against us.","ref":"Lamentations 5:22","synthesized":"unless You have utterly rejected us and remain angry with us beyond measure.","sources":{"KJV":{"text":"But thou hast utterly rejected us; thou art very wroth against us."},"BSB":{"text":"unless You have utterly rejected us and remain angry with us beyond measure."}},"definableWords":[],"peopleInVerse":[]}}}};